import{_ as i,c as a,o as n,ak as s,ao as t}from"./chunks/framework.DHLlVITf.js";const p=JSON.parse('{"title":"AireGlu Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireglu-v1-119-0.md","filePath":"aireblock-releases/aireglu-v1-119-0.md","lastUpdated":1784559694000}'),l={name:"aireblock-releases/aireglu-v1-119-0.md"};function o(r,e,d,u,c,g){return n(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="aireglu-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+t+'"> AireGlu Release Notes</span> <a class="header-anchor" href="#aireglu-release-notes" aria-label="Permalink to “AireGlu Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 1.119.0<br><strong>Release Date:</strong> 29 July 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Added In A New V2 Liquid Engine</li><li>Support For Running Our existing V1 Liquid Engine Alongside Our New V2 Liquid Engine (GLU-3127)</li><li>Liquid Engine V2 Is Now The Default For New Tasks (GLU-3128)</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Fixed Single-Item XML Arrays Not Recognised As Arrays In Liquid Mapping (Fix Only Available In The V2 Liquid Engine) (GLU-505)</li><li>Fixed Conditional Liquid Evaluation For XML Elements With Attributes (Fix Only Available In The V2 Liquid Engine) (GLU-2807)</li><li>Fixed Job Task Content Overflow Display Issue (GLU-3196)</li></ul><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="support-for-running-our-existing-v1-liquid-engine-alongside-our-new-v2-liquid-engine-glu-3127" tabindex="-1">Support For Running Our existing V1 Liquid Engine Alongside Our New V2 Liquid Engine (GLU-3127) <a class="header-anchor" href="#support-for-running-our-existing-v1-liquid-engine-alongside-our-new-v2-liquid-engine-glu-3127" aria-label="Permalink to “Support For Running Our existing V1 Liquid Engine Alongside Our New V2 Liquid Engine (GLU-3127)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Added support for running the V1 and V2 Liquid engines side by side, allowing the mapping engine used by a task to be selected based on the configured Liquid version.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You will be able to see what Liquid engine version powers your mapping tasks. Existing tasks will remain using V1, however, you will now have the option to recreate the task or create new tasks using the V2 Liquid engine in order to make use of the enhanced capabilities.</p></div><h4 id="liquid-engine-v2-now-default-for-new-tasks-glu-3128" tabindex="-1">Liquid Engine V2 Now Default For New Tasks (GLU-3128) <a class="header-anchor" href="#liquid-engine-v2-now-default-for-new-tasks-glu-3128" aria-label="Permalink to “Liquid Engine V2 Now Default For New Tasks (GLU-3128)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>New tasks now default to the V2 Liquid engine, while existing tasks continue to use V1 by default.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Any new mapping tasks you create will automatically benefit from the latest V2 engine, while your existing tasks continue working exactly as before.</p></div><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="fixed-single-item-xml-arrays-not-recognised-as-arrays-in-liquid-mapping-fix-only-available-in-the-v2-liquid-engine-glu-505" tabindex="-1">Fixed Single-Item XML Arrays Not Recognised As Arrays In Liquid Mapping (Fix Only Available In The V2 Liquid Engine) (GLU-505) <a class="header-anchor" href="#fixed-single-item-xml-arrays-not-recognised-as-arrays-in-liquid-mapping-fix-only-available-in-the-v2-liquid-engine-glu-505" aria-label="Permalink to “Fixed Single-Item XML Arrays Not Recognised As Arrays In Liquid Mapping (Fix Only Available In The V2 Liquid Engine) (GLU-505)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where an XML array containing only a single item was not recognised as an array during Liquid mapping, causing loop and array-based templates to behave incorrectly for single-item collections. You now have the ability to use filters such as <code>.size</code>, <code>.first</code>, and <code>.last</code> on these single-item arrays.</p></div><h4 id="fixed-conditional-liquid-evaluation-for-xml-elements-with-attributes-fix-only-available-in-the-v2-liquid-engine-glu-2807" tabindex="-1">Fixed Conditional Liquid Evaluation For XML Elements With Attributes (Fix Only Available In The V2 Liquid Engine) (GLU-2807) <a class="header-anchor" href="#fixed-conditional-liquid-evaluation-for-xml-elements-with-attributes-fix-only-available-in-the-v2-liquid-engine-glu-2807" aria-label="Permalink to “Fixed Conditional Liquid Evaluation For XML Elements With Attributes (Fix Only Available In The V2 Liquid Engine) (GLU-2807)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where conditional Liquid expressions evaluated incorrectly for XML elements that had attributes, even though printing those elements worked correctly.</p></div><h4 id="fixed-job-task-content-overflow-display-issue-glu-3196" tabindex="-1">Fixed Job Task Content Overflow Display Issue (GLU-3196) <a class="header-anchor" href="#fixed-job-task-content-overflow-display-issue-glu-3196" aria-label="Permalink to “Fixed Job Task Content Overflow Display Issue (GLU-3196)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed a display issue where content within a Job Task rendered longer than its containing box, causing the content to overflow the UI.</p></div>',25)])])}const b=i(l,[["render",o]]);export{p as __pageData,b as default};
